def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        base = np.exp(-item / (capacity + 1))
        factor = 1.0
        complexity = 0.0
        bonus = 1.0
        decay = 1.0
        steps = 15
        for step in range(1, steps + 1):
            mod1 = (capacity * step) % 13
            mod2 = (capacity + step * step) % 9
            mod3 = (capacity - step) % 11
            if mod1 == 0:
                factor *= 1.03 + 0.02 * (step % 5)
            elif mod2 < 3:
                factor *= 0.97 - 0.01 * (step % 4)
            else:
                factor *= 1.01
            if item / (capacity + 0.1) > 0.9 and step % 4 == 0:
                bonus *= 1.08 + 0.015 * step
            elif item / (capacity + 0.1) < 0.15 and step % 3 == 0:
                bonus *= 0.85 - 0.012 * step
            if mod3 == 7:
                complexity += np.tanh(step / (item + 1)) * np.log1p(capacity + step)
            else:
                complexity += (np.sin(step * item) + np.cos(capacity / (step + 1))) / (step + 2)
            if step == 10:
                for inner in range(1, 8):
                    diff = capacity - item * inner * inner
                    if diff > 5:
                        complexity -= np.exp(-diff / (inner + 1)) * 0.4
                    else:
                        complexity += np.sqrt(abs(diff)) / (inner + 2)
            if step % 5 == 0:
                decay *= 0.93 + 0.01 * (step // 5)
            else:
                decay *= 1.02 - 0.005 * (step % 3)
